sql:
SELECT * FROM benchmark_jobs
WHERE job_platform = '.NET Core 3.1'
AND job_status = 'Completed';

SELECT job_id
FROM job_history
WHERE execution_status = 'Success';

SELECT AVG(job_duration) AS average_job_duration
FROM benchmark_jobs
WHERE job_start_time BETWEEN '2023-01-01 10:00:00' AND '2023-01-02 10:00:00';

SELECT target, SUM(job_duration) AS total_duration
FROM benchmark_jobs
GROUP BY target;

SELECT job_id 
FROM benchmark_jobs
WHERE job_duration = (SELECT MAX(job_duration) FROM benchmark_jobs);

SELECT job_duration, target_method
FROM benchmark_jobs
WHERE job_duration > 300;

SELECT COUNT(job_id)
FROM (
    SELECT job_id FROM benchmark_jobs WHERE job_status = 'Failed'
    UNION
    SELECT job_id FROM job_history WHERE execution_status = 'Success'
);

SELECT bj.target, AVG(bj.job_duration) AS average_duration
FROM benchmark_jobs bj
GROUP BY bj.target;

SELECT job_id, target_namespace 
FROM benchmark_jobs 
WHERE job_id = 0;

SELECT tool_name, tool_version
FROM benchmark_tools
WHERE job_id = 0;

